    if (curr.length === n) {
        result.push(curr);
        return;
    }

    // Always try adding '0'
    generate(n, curr + "0", result);

    // Add '1' only if previous char is not '1'
    if (curr.length === 0 || curr[curr.length - 1] !== '1') {
        generate(n, curr + "1", result);
    }
}

function main() {
    // Input length n
    const n = 3;

    // Array to store results
